<template>
  <div class="page-shell">
    <section class="calendar-card content-card">
      <div class="calendar-header">
        <div class="calendar-heading">
          <span class="eyebrow">Calendar</span>
          <h1>{{ calendarTitle }}</h1>
          <p>{{ calendarSubtitle }}</p>
        </div>

        <div class="calendar-toolbar">
          <div class="view-switch" aria-label="Calendar views">
            <button
              v-for="mode in viewModes"
              :key="mode.key"
              type="button"
              class="view-btn"
              :class="{ active: viewMode === mode.key }"
              @click="setView(mode.key)"
            >
              {{ mode.label }}
            </button>
          </div>

          <div class="nav-switch" aria-label="Calendar navigation">
            <button type="button" class="nav-btn" @click="goPrevious">Prev</button>
            <button type="button" class="nav-btn today-btn" @click="goToday">Today</button>
            <button type="button" class="nav-btn" @click="goNext">Next</button>
          </div>
        </div>
      </div>

      <div class="calendar-layout">
        <div class="calendar-main">
          <template v-if="viewMode === 'day'">
            <div class="day-view">
              <span class="day-tag">{{ weekdayName(selectedDate) }}</span>
              <div class="day-number">{{ selectedDate.getDate() }}</div>
              <div class="day-meta">
                <div>{{ monthName(selectedDate) }} {{ selectedDate.getFullYear() }}</div>
                <div class="muted-line">{{ formatLongDate(selectedDate) }}</div>
              </div>
            </div>
          </template>

          <template v-else-if="viewMode === 'week'">
            <div class="week-view">
              <button
                v-for="day in weekCells"
                :key="day.key"
                type="button"
                class="week-cell"
                :class="{ active: isSameDate(day.date, selectedDate), today: isToday(day.date) }"
                @click="selectDate(day.date)"
              >
                <span class="week-name">{{ day.weekdayShort }}</span>
                <strong class="week-number">{{ day.dayNumber }}</strong>
                <span class="week-month">{{ day.monthShort }}</span>
              </button>
            </div>
          </template>

          <template v-else-if="viewMode === 'month'">
            <div class="month-view">
              <div class="weekday-row">
                <span v-for="label in weekdayShortNames" :key="label">{{ label }}</span>
              </div>
              <div class="month-grid">
                <button
                  v-for="cell in monthCells"
                  :key="cell.key"
                  type="button"
                  class="month-cell"
                  :class="{ outside: !cell.inMonth, active: cell.isSelected, today: cell.isToday }"
                  @click="selectDate(cell.date)"
                >
                  <span class="month-day">{{ cell.day }}</span>
                  <span class="month-dot">{{ cell.monthShort }}</span>
                </button>
              </div>
            </div>
          </template>

          <template v-else>
            <div class="year-view">
              <div class="year-grid">
                <button
                  v-for="(month, index) in yearMonths"
                  :key="month.key"
                  type="button"
                  class="year-cell"
                  :class="{ active: month.isActive, today: month.isCurrent }"
                  @click="openMonth(index)"
                >
                  <span class="year-month-index">{{ month.short }}</span>
                  <strong>{{ month.long }}</strong>
                </button>
              </div>
            </div>
          </template>
        </div>

        <aside class="calendar-summary">
          <div class="summary-card">
            <span class="summary-tag">Selected</span>
            <h2>{{ formatLongDate(selectedDate) }}</h2>
            <p>{{ calendarSummary }}</p>
          </div>

