            </div>
            <div class="summary-item">
              <span>Year</span>
              <strong>{{ selectedDate.getFullYear() }}</strong>
            </div>
            <div class="summary-item">
              <span>View</span>
              <strong>{{ viewLabel }}</strong>
            </div>
          </div>
        </aside>
      </div>
