</template>

<script>
export default {
  data() {
    return {
      viewMode: "month",
      selectedDate: new Date(),
      viewModes: [
        { key: "day", label: "Day" },
        { key: "week", label: "Week" },
        { key: "month", label: "Month" },
        { key: "year", label: "Year" },
      ],
      weekdayShortNames: ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"],
      weekdayNames: ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"],
      monthNames: [
        "January",
        "February",
        "March",
        "April",
        "May",
        "June",
        "July",
        "August",
        "September",
        "October",
        "November",
        "December",
      ],
      activities: [
        {
          date: "2022-09",
          title: "Group Meeting",
          description: "Team building with Prof. Yang Li and Prof. Faisal Nadeem Khan.",
          image: "/photo/group meeting.jpg",
          alt: "Group Meeting September 2022",
        },
        {
          date: "2022-12",
          title: "Field Visit",
          description: "Team building in the Shenzhen International Garden and Flower Expo Park.",
          image: "/photo/groupmeeting2.jpeg",
          alt: "Group Meeting December 2022",
        },
      ],
    };
  },
  computed: {
    calendarTitle() {
      if (this.viewMode === "day") {
        return this.formatLongDate(this.selectedDate);
      }

      if (this.viewMode === "week") {
        return `Week view: ${this.formatWeekRange(this.selectedDate)}`;
      }

      if (this.viewMode === "year") {
        return `${this.selectedDate.getFullYear()} Overview`;
      }

      return this.formatMonthLabel(this.selectedDate);
    },
    calendarSubtitle() {
      if (this.viewMode === "day") {
        return "Inspect a single date with weekday, month, and year details.";
      }

      if (this.viewMode === "week") {
        return "Browse the full seven-day span around the selected date.";
      }

      if (this.viewMode === "year") {
        return "Jump across the full year and open any month with one click.";
      }

      return "Use the month grid to compare weekdays and adjacent dates at a glance.";
    },
    calendarSummary() {
      if (this.viewMode === "day") {
        return "Focused daily detail view with a large date marker.";
      }

      if (this.viewMode === "week") {
        return `The current week runs from ${this.formatShortDate(this.getWeekStart(this.selectedDate))} to ${this.formatShortDate(
          this.getWeekEnd(this.selectedDate)
        )}.`;
      }

      if (this.viewMode === "year") {
        return "Twelve month cards are shown for fast navigation across the whole year.";
      }

      return "The monthly grid includes adjacent days so the calendar stays continuous.";
    },
    viewLabel() {
      const current = this.viewModes.find((mode) => mode.key === this.viewMode);
      return current ? current.label : "Month";
    },
    monthCells() {
      const firstOfMonth = new Date(this.selectedDate.getFullYear(), this.selectedDate.getMonth(), 1);
      const gridStart = this.addDays(firstOfMonth, -firstOfMonth.getDay());

      return Array.from({ length: 42 }, (_, index) => {
        const date = this.addDays(gridStart, index);
        return {
          key: `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`,
          date,
          day: date.getDate(),
          monthShort: this.monthNames[date.getMonth()].slice(0, 3),
          inMonth: date.getMonth() === this.selectedDate.getMonth(),
          isToday: this.isToday(date),
          isSelected: this.isSameDate(date, this.selectedDate),
        };
      });
    },
    weekCells() {
      const start = this.getWeekStart(this.selectedDate);

      return Array.from({ length: 7 }, (_, index) => {
        const date = this.addDays(start, index);
        return {
          key: `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`,
          date,
          weekdayShort: this.weekdayShortNames[date.getDay()],
          dayNumber: date.getDate(),
          monthShort: this.monthNames[date.getMonth()].slice(0, 3),
        };
      });
    },
    yearMonths() {
      const year = this.selectedDate.getFullYear();
      const today = new Date();

      return this.monthNames.map((month, index) => {
        const date = new Date(year, index, 1);
        return {
          key: `${year}-${index + 1}`,
          long: month,
          short: month.slice(0, 3),
          isActive: index === this.selectedDate.getMonth(),
          isCurrent: today.getFullYear() === year && today.getMonth() === index,
        };
      });
    },
  },
  methods: {
    setView(mode) {
      this.viewMode = mode;
    },
    goToday() {
      this.selectedDate = this.cloneDate(new Date());
    },
    goPrevious() {
      if (this.viewMode === "day") {
        this.selectedDate = this.addDays(this.selectedDate, -1);
        return;
      }

      if (this.viewMode === "week") {
        this.selectedDate = this.addDays(this.selectedDate, -7);
        return;
      }

      if (this.viewMode === "year") {
        this.selectedDate = this.addYears(this.selectedDate, -1);
        return;
      }

      this.selectedDate = this.addMonths(this.selectedDate, -1);
    },
    goNext() {
      if (this.viewMode === "day") {
        this.selectedDate = this.addDays(this.selectedDate, 1);
        return;
      }

      if (this.viewMode === "week") {
        this.selectedDate = this.addDays(this.selectedDate, 7);
        return;
      }

      if (this.viewMode === "year") {
        this.selectedDate = this.addYears(this.selectedDate, 1);
        return;
      }

      this.selectedDate = this.addMonths(this.selectedDate, 1);
    },
    selectDate(date) {
      this.selectedDate = this.cloneDate(date);
    },
    openMonth(index) {
      const next = this.cloneDate(this.selectedDate);
      next.setDate(1);
      next.setMonth(index);
      this.selectedDate = next;
      this.viewMode = "month";
    },
    cloneDate(date) {
      return new Date(date.getFullYear(), date.getMonth(), date.getDate());
    },
    addDays(date, amount) {
      const next = this.cloneDate(date);
      next.setDate(next.getDate() + amount);
      return next;
    },
    addMonths(date, amount) {
      const next = this.cloneDate(date);
      const day = next.getDate();
      next.setDate(1);
      next.setMonth(next.getMonth() + amount);
      const maxDay = new Date(next.getFullYear(), next.getMonth() + 1, 0).getDate();
      next.setDate(Math.min(day, maxDay));
      return next;
    },
    addYears(date, amount) {
      const next = this.cloneDate(date);
      const day = next.getDate();
      const month = next.getMonth();
      next.setFullYear(next.getFullYear() + amount);
      const maxDay = new Date(next.getFullYear(), month + 1, 0).getDate();
      next.setMonth(month);
      next.setDate(Math.min(day, maxDay));
      return next;
    },
    getWeekStart(date) {
      return this.addDays(date, -date.getDay());
    },
    getWeekEnd(date) {
      return this.addDays(this.getWeekStart(date), 6);
    },
    weekdayName(date) {
      return this.weekdayNames[date.getDay()];
    },
    monthName(date) {
      return this.monthNames[date.getMonth()];
    },
    formatMonthLabel(date) {
      return `${this.monthName(date)} ${date.getFullYear()}`;
    },
    formatShortDate(date) {
      return `${this.monthNames[date.getMonth()].slice(0, 3)} ${date.getDate()}`;
    },
    formatLongDate(date) {
      return `${this.weekdayName(date)}, ${this.monthName(date)} ${date.getDate()}, ${date.getFullYear()}`;
    },
    formatWeekRange(date) {
      const start = this.getWeekStart(date);
      const end = this.getWeekEnd(date);

      if (start.getFullYear() === end.getFullYear() && start.getMonth() === end.getMonth()) {
        return `${this.monthNames[start.getMonth()]} ${start.getDate()} - ${end.getDate()}, ${end.getFullYear()}`;
      }

      if (start.getFullYear() === end.getFullYear()) {
        return `${this.formatShortDate(start)} - ${this.formatShortDate(end)}, ${end.getFullYear()}`;
      }

      return `${this.formatShortDate(start)}, ${start.getFullYear()} - ${this.formatShortDate(end)}, ${end.getFullYear()}`;
    },
    isSameDate(left, right) {
      return (
        left.getFullYear() === right.getFullYear() &&
        left.getMonth() === right.getMonth() &&
        left.getDate() === right.getDate()
      );
    },
    isToday(date) {
      const today = new Date();
      return this.isSameDate(date, today);
    },
  },
};
</script>

